import React, { useEffect, useState, useCallback } from 'react';
import api from '../utils/api';

const ST = (s: string) => {
  const m: any = {
    borrowed:{ bg:'rgba(245,158,11,0.12)', color:'#d97706' },
    returned:{ bg:'rgba(16,185,129,0.12)',  color:'#059669' },
    overdue: { bg:'rgba(239,68,68,0.12)',   color:'#dc2626' },
    pending: { bg:'rgba(245,158,11,0.12)',  color:'#d97706' },
    approved:{ bg:'rgba(16,185,129,0.12)',  color:'#059669' },
    rejected:{ bg:'rgba(239,68,68,0.12)',   color:'#dc2626' },
  };
  return m[s] || { bg:'rgba(107,114,128,0.12)', color:'#6b7280' };
};

export default function MyBorrows() {
  const [borrows, setBorrows]   = useState<any[]>([]);
  const [requests, setRequests] = useState<any[]>([]);
  const [deleted, setDeleted]   = useState<any[]>([]);
  const [loading, setLoading]   = useState(true);
  const [delLoading, setDelLoading] = useState(false);
  const [tab, setTab] = useState<'requests'|'borrows'|'deleted'>('requests');
  const [busy, setBusy] = useState<Set<string>>(new Set()); // track in-progress ops

  const load = useCallback(() => {
    setLoading(true);
    Promise.all([api.get('/borrows/my'), api.get('/borrows/my-requests')])
      .then(([b,r]) => {
        setBorrows(b.data.data||[]);
        setRequests(r.data.data||[]);
      })
      .finally(() => setLoading(false));
  }, []);

  const loadDeleted = useCallback(async () => {
    setDelLoading(true);
    try {
      const { data } = await api.get('/borrows/my-deleted');
      setDeleted(data.data||[]);
    } catch { setDeleted([]); }
    finally { setDelLoading(false); }
  }, []);

  useEffect(() => { load(); }, [load]);

  const isBusy = (key: string) => busy.has(key);
  const setBusyKey = (key: string, val: boolean) => setBusy(prev => {
    const next = new Set(prev);
    val ? next.add(key) : next.delete(key);
    return next;
  });

  const hideRequest = async (id: number) => {
    const key = `req-${id}`;
    if (isBusy(key)) return;
    setBusyKey(key, true);
    // Optimistic
    setRequests(p => p.filter(x => x.id !== id));
    try {
      await api.delete(`/borrows/my-requests/${id}`);
      // Reload deleted list if open
      if (tab === 'deleted') loadDeleted();
    } catch {
      // Rollback on error
      load();
    } finally { setBusyKey(key, false); }
  };

  const hideBorrow = async (id: number) => {
    const key = `borrow-${id}`;
    if (isBusy(key)) return;
    setBusyKey(key, true);
    setBorrows(p => p.filter(x => x.id !== id));
    try {
      await api.delete(`/borrows/my-borrows/${id}`);
      if (tab === 'deleted') loadDeleted();
    } catch {
      load();
    } finally { setBusyKey(key, false); }
  };

  const restore = async (id: number, item_type: string) => {
    const key = `restore-${item_type}-${id}`;
    if (isBusy(key)) return;
    setBusyKey(key, true);
    // Optimistic remove from deleted list
    setDeleted(p => p.filter(x => !(x.id === id && x.item_type === item_type)));
    try {
      await api.put(`/borrows/my-deleted/${id}/restore`, { item_type });
      // Reload the relevant list from server (ensures no duplicates)
      load();
    } catch {
      // rollback
      loadDeleted();
    } finally { setBusyKey(key, false); }
  };

  const deleteFromTrash = async (id: number, item_type: string) => {
    const key = `trash-${item_type}-${id}`;
    if (isBusy(key)) return;
    setBusyKey(key, true);
    // Optimistic remove
    setDeleted(p => p.filter(x => !(x.id === id && x.item_type === item_type)));
    try {
      await api.delete(`/borrows/my-deleted/${id}`, { data: { item_type } });
    } catch {
      // Rollback on error
      loadDeleted();
    } finally { setBusyKey(key, false); }
  };

  const pendingCount = requests.filter(r => r.status === 'pending').length;

  const DelBtn = ({ onClick, disabled }: { onClick:()=>void, disabled?:boolean }) => (
    <button onClick={onClick} disabled={disabled} title="Move to Recently Deleted"
      style={{ width:32,height:32,borderRadius:8,background:'var(--bg3)',border:'1px solid var(--border)',
        color:'var(--text-muted)',cursor:disabled?'default':'pointer',
        display:'flex',alignItems:'center',justifyContent:'center',
        fontSize:14,transition:'all .18s',flexShrink:0,opacity:disabled?.4:1
      }}
      onMouseEnter={e=>{ if(!disabled){const b=e.currentTarget;b.style.background='rgba(239,68,68,0.1)';b.style.color='#ef4444';b.style.borderColor='rgba(239,68,68,0.25)'; }}}
      onMouseLeave={e=>{ const b=e.currentTarget;b.style.background='var(--bg3)';b.style.color='var(--text-muted)';b.style.borderColor='var(--border)'; }}>
      🗑
    </button>
  );

  return (
    <div className="page-enter" style={{padding:'32px 40px',width:'100%'}}>

      <div style={{marginBottom:28}}>
        <h1 style={{fontFamily:"'Playfair Display',serif",fontSize:32,fontWeight:700,color:'var(--text)'}}>My Library</h1>
        <p style={{color:'var(--text-muted)',fontSize:14,marginTop:6}}>Your borrow history and requests</p>
      </div>

      {/* Tabs */}
      <div style={{display:'flex',gap:8,marginBottom:26,flexWrap:'wrap'}}>
        {([
          { key:'requests', label:'My Requests' },
          { key:'borrows',  label:'Borrowed Books' },
          { key:'deleted',  label:'Recently Deleted' },
        ] as const).map(t => (
          <button key={t.key}
            onClick={() => { setTab(t.key); if(t.key==='deleted') loadDeleted(); }}
            style={{
              padding:'10px 20px',
              background: tab===t.key
                ? (t.key==='deleted' ? 'rgba(239,68,68,0.12)' : '#c9a84c')
                : 'var(--bg2)',
              color: tab===t.key
                ? (t.key==='deleted' ? '#ef4444' : '#1a1a2e')
                : 'var(--text-dim)',
              border: tab===t.key
                ? (t.key==='deleted' ? '1px solid rgba(239,68,68,0.25)' : 'none')
                : '1px solid var(--border)',
              borderRadius:10,fontSize:13.5,fontWeight:700,fontFamily:'inherit',
              cursor:'pointer',transition:'all .2s',display:'flex',alignItems:'center',gap:8,
              boxShadow: tab===t.key && t.key!=='deleted' ? '0 4px 14px rgba(201,168,76,0.3)' : 'none',
            }}>
            {t.key==='deleted' && <span style={{fontSize:12}}>🗑</span>}
            {t.label}
            {t.key==='requests' && pendingCount>0 && (
              <span style={{background:'#1a1a2e',color:'#c9a84c',borderRadius:99,padding:'1px 8px',fontSize:11,fontWeight:800}}>
                {pendingCount}
              </span>
            )}
          </button>
        ))}
      </div>

      {/* ─ Content ─ */}
      {loading && tab !== 'deleted' ? (
        <div style={{display:'flex',justifyContent:'center',padding:80}}>
          <div style={{width:32,height:32,border:'3px solid #c9a84c',borderTopColor:'transparent',borderRadius:'50%',animation:'spin 1s linear infinite'}}/>
        </div>

      ) : tab === 'requests' ? (
        requests.length ? (
          <div style={{display:'grid',gap:12}}>
            {requests.map(r => {
              const st = ST(r.status);
              const canDel = r.status==='rejected' || r.status==='approved';
              return (
                <div key={r.id} className="hover-card"
                  style={{background:'var(--bg2)',border:'1px solid var(--border)',borderRadius:16,padding:'18px 22px',display:'flex',alignItems:'center',gap:16}}>
                  <div style={{width:10,height:10,borderRadius:'50%',background:st.color,flexShrink:0,boxShadow:`0 0 8px ${st.color}66`}}/>
                  <div style={{flex:1,minWidth:0}}>
                    <div style={{fontSize:15,fontWeight:700,color:'var(--text)',overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>{r.title}</div>
                    <div style={{fontSize:13,color:'var(--text-dim)',marginTop:2}}>{r.author}</div>
                    <div style={{fontSize:12,color:'var(--text-muted)',marginTop:5}}>
                      Requested: {new Date(r.request_date).toLocaleDateString('en-GB',{day:'numeric',month:'short',year:'numeric'})}
                    </div>
                  </div>
                  <div style={{display:'flex',alignItems:'center',gap:10,flexShrink:0}}>
                    <div style={{textAlign:'right'}}>
                      <span style={{fontSize:12,fontWeight:700,padding:'5px 13px',borderRadius:99,background:st.bg,color:st.color,textTransform:'capitalize'}}>{r.status}</span>
                      {r.reject_reason && <div style={{fontSize:11,color:'#dc2626',marginTop:4,maxWidth:180,textAlign:'right'}}>Reason: {r.reject_reason}</div>}
                    </div>
                    {canDel && <DelBtn onClick={()=>hideRequest(r.id)} disabled={isBusy(`req-${r.id}`)}/>}
                  </div>
                </div>
              );
            })}
          </div>
        ) : (
          <div style={{textAlign:'center',padding:'80px 0'}}>
            <div style={{fontSize:14,color:'var(--text-muted)',fontStyle:'italic',marginBottom:8}}>No requests yet</div>
            <div style={{fontSize:13,color:'var(--text-muted)'}}>Go to Books page and click "Request Borrow"</div>
          </div>
        )

      ) : tab === 'borrows' ? (
        borrows.length ? (
          <div style={{display:'grid',gap:12}}>
            {borrows.map(b => {
              const st = ST(b.status);
              return (
                <div key={b.id} className="hover-card"
                  style={{background:'var(--bg2)',border:`1px solid ${b.status==='overdue'?'rgba(239,68,68,0.3)':'var(--border)'}`,borderRadius:16,padding:'18px 22px',display:'flex',alignItems:'center',gap:16}}>
                  <div style={{width:10,height:10,borderRadius:'50%',background:st.color,flexShrink:0,boxShadow:`0 0 8px ${st.color}66`}}/>
                  <div style={{flex:1,minWidth:0}}>
                    <div style={{fontSize:15,fontWeight:700,color:'var(--text)',overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>{b.title}</div>
                    <div style={{fontSize:13,color:'var(--text-dim)',marginTop:2}}>{b.author}</div>
                    <div style={{fontSize:12,color:'var(--text-muted)',marginTop:5}}>Due: {b.due_date?.split('T')[0]}</div>
                  </div>
                  <div style={{display:'flex',alignItems:'center',gap:10,flexShrink:0}}>
                    <div style={{textAlign:'right'}}>
                      <span style={{fontSize:12,fontWeight:700,padding:'5px 13px',borderRadius:99,background:st.bg,color:st.color,textTransform:'capitalize',display:'inline-block',marginBottom:b.fine_amount>0?4:0}}>{b.status}</span>
                      {b.fine_amount>0 && <div style={{fontSize:13,fontWeight:800,color:'#dc2626'}}>Fine: ৳{Number(b.fine_amount).toFixed(2)}</div>}
                    </div>
                    {b.status==='returned' && <DelBtn onClick={()=>hideBorrow(b.id)} disabled={isBusy(`borrow-${b.id}`)}/>}
                  </div>
                </div>
              );
            })}
          </div>
        ) : (
          <div style={{textAlign:'center',padding:'80px 0',color:'var(--text-muted)',fontSize:14,fontStyle:'italic'}}>No books borrowed yet</div>
        )

      ) : (
        /* ─ Recently Deleted ─ */
        <div>
          <p style={{fontSize:13,color:'var(--text-muted)',marginBottom:20}}>
            Items are kept here for <strong style={{color:'var(--text-dim)'}}>30 days</strong>, then permanently removed. You can restore or delete them anytime.
          </p>
          {delLoading ? (
            <div style={{display:'flex',justifyContent:'center',padding:60}}>
              <div style={{width:28,height:28,border:'3px solid #ef4444',borderTopColor:'transparent',borderRadius:'50%',animation:'spin 1s linear infinite'}}/>
            </div>
          ) : deleted.length ? (
            <div style={{display:'grid',gap:12}}>
              {deleted.map(item => {
                const st = ST(item.status);
                const rKey = `restore-${item.item_type}-${item.id}`;
                const dKey = `trash-${item.item_type}-${item.id}`;
                return (
                  <div key={`${item.item_type}-${item.id}`}
                    style={{background:'var(--bg2)',border:'1px solid var(--border)',borderRadius:16,padding:'18px 22px',display:'flex',alignItems:'center',gap:16,opacity:.8}}>
                    <div style={{width:36,height:36,borderRadius:10,background:'var(--bg3)',border:'1px solid var(--border)',display:'flex',alignItems:'center',justifyContent:'center',flexShrink:0,fontSize:16}}>
                      {item.item_type==='borrow'?'📚':'📋'}
                    </div>
                    <div style={{flex:1,minWidth:0}}>
                      <div style={{fontSize:15,fontWeight:700,color:'var(--text)',overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>{item.title}</div>
                      <div style={{fontSize:13,color:'var(--text-dim)',marginTop:2}}>{item.author}</div>
                      <div style={{display:'flex',alignItems:'center',gap:8,marginTop:6}}>
                        <span style={{fontSize:10,fontWeight:700,padding:'2px 8px',borderRadius:99,background:st.bg,color:st.color,textTransform:'capitalize'}}>{item.status}</span>
                        <span style={{fontSize:11,color:'var(--text-muted)'}}>{item.item_type==='borrow'?'Borrow':'Request'}</span>
                        {item.deleted_at && (
                          <span style={{fontSize:11,color:'var(--text-muted)'}}>
                            · Deleted {new Date(item.deleted_at).toLocaleDateString('en-GB',{day:'numeric',month:'short'})}
                          </span>
                        )}
                      </div>
                    </div>
                    {/* Actions */}
                    <div style={{display:'flex',gap:8,flexShrink:0}}>
                      <button onClick={()=>restore(item.id,item.item_type)} disabled={isBusy(rKey)}
                        style={{padding:'7px 14px',borderRadius:9,background:'rgba(16,185,129,0.1)',border:'1px solid rgba(16,185,129,0.25)',color:'#10b981',cursor:isBusy(rKey)?'default':'pointer',fontSize:12,fontWeight:700,fontFamily:'inherit',transition:'all .18s',opacity:isBusy(rKey)?.5:1}}
                        onMouseEnter={e=>{if(!isBusy(rKey))e.currentTarget.style.background='rgba(16,185,129,0.2)';}}
                        onMouseLeave={e=>{e.currentTarget.style.background='rgba(16,185,129,0.1)';}}>
                        ↩ Restore
                      </button>
                      <button onClick={()=>deleteFromTrash(item.id,item.item_type)} disabled={isBusy(dKey)}
                        style={{width:32,height:32,borderRadius:8,background:'rgba(239,68,68,0.08)',border:'1px solid rgba(239,68,68,0.15)',color:'#ef4444',cursor:isBusy(dKey)?'default':'pointer',display:'flex',alignItems:'center',justifyContent:'center',fontSize:13,transition:'all .18s',opacity:isBusy(dKey)?.5:1}}
                        onMouseEnter={e=>{if(!isBusy(dKey))e.currentTarget.style.background='rgba(239,68,68,0.18)';}}
                        onMouseLeave={e=>{e.currentTarget.style.background='rgba(239,68,68,0.08)';}}>
                        🗑
                      </button>
                    </div>
                  </div>
                );
              })}
            </div>
          ) : (
            <div style={{textAlign:'center',padding:'70px 0'}}>
              <div style={{fontSize:36,marginBottom:12,opacity:.25}}>🗑️</div>
              <div style={{fontSize:14,color:'var(--text-muted)',fontStyle:'italic'}}>Recently Deleted is empty</div>
            </div>
          )}
        </div>
      )}
    </div>
  );
}
